ee:message.ee:set-payload:
%dw 2.0
output application/json

var actionMap = {
    "SNOWFLAKE_RETRIEVAL": { 
        status: "SNOWFLAKE_FAILURE", 
        action: if (vars.retryable) "RETRY_ON_NEXT_POLL" else "MANUAL_REVIEW_REQUIRED" 
    },
    "GOOGLE_DRIVE_UPLOAD": { 
        status: "UPLOAD_FAILED", 
        action: if (vars.retryable) "RETRY_ELIGIBLE" else "MANUAL_INTERVENTION_REQUIRED" 
    },
    "OBJECT_STORE_ERROR": { 
        status: "TRACKING_FAILED", 
        action: "CHECK_OBJECT_STORE_CONFIG" 
    },
    "SECURITY_AUTH_FAILURE": { 
        status: "AUTH_FAILURE", 
        action: "MANUAL_INTERVENTION_REQUIRED" 
    },
    "DATAWEAVE_TRANSFORMATION": { 
        status: "TRANSFORMATION_FAILED", 
        action: "ROW_SKIPPED_DATA_ISSUE" 
    },
    "CONNECTIVITY": { 
        status: "CONNECTIVITY_FAILED", 
        action: "RETRY_ON_NEXT_POLL" 
    },
    "UNCLASSIFIED": { 
        status: "UNCLASSIFIED_FAILURE", 
        action: "MANUAL_REVIEW_REQUIRED" 
    }
}

var outcome = actionMap[vars.errorCategory] default actionMap."UNCLASSIFIED"

---
{
    (vars.errorMeta default {}),
    (outcome)
}
